} record;

typedef struct {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    char is_leaf;
    int num_keys;
} knode;

__kernel void findK(
    long maxheight,
    __global knode *knodes,
    long knodes_elem,
    __global record *records,
    __global long *currKnode,
    __global long *offset,
    __global int *keys,
    __global record *ans)
{
    int bid = get_group_id(0);
    int thid = get_local_id(0);
    int threadsPerBlock = get_local_size(0);

    long current_knode_idx = currKnode[bid];
    long offset_val = offset[bid];
    int key_val = keys[bid];

    for (long i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            int k_idx = (int)current_knode_idx;
            if (knodes[k_idx].keys[thid] <= key_val && knodes[k_idx].keys[thid + 1] > key_val) {
                long next_idx = knodes[offset_val].indices[thid];
                if (next_idx < knodes_elem) {
                    offset_val = next_idx;
                }
            }
        }
        current_knode_idx = offset_val;
    }

    if (thid < threadsPerBlock) {
        int k_idx = (int)current_knode_idx;
        if (knodes[k_idx].keys[thid] == key_val) {
            long rec_idx = knodes[k_idx].indices[thid];
            ans[bid].value = records[rec_idx].value;
        }
    }

    if (thid == 0) {
        currKnode[bid] = current_knode_idx;
        offset[bid] = offset_val;
    }
}

